}

function mpd_get_user_profile_row($user_id) {
	global $wpdb;

	$table = $wpdb->prefix . 'users';
	$sql = "SELECT ID, user_login, user_nicename, user_email, user_url, user_registered, display_name
	        FROM {$table}
	        WHERE ID = %d
	        LIMIT 1";

	return $wpdb->get_row($wpdb->prepare($sql, $user_id), ARRAY_A);
}

